<?php

namespace Drupal\my_module\Service;

use Drupal\Core\Entity\EntityTypeManagerInterface;

class ContentAggregator {

  protected $entityTypeManager;
  protected $database;

  public function __construct(EntityTypeManagerInterface $entity_type_manager, $database) {
    $this->entityTypeManager = $entity_type_manager;
    $this->database = $database;
  }

  public function getRecentArticles($limit = 10) {
    $nids = \Drupal::entityQuery('node')
      ->condition('type', 'article')
      ->condition('status', 1)
      ->sort('created', 'DESC')
      ->range(0, $limit)
      ->execute();

    $nodes = \Drupal::entityTypeManager()->loadMultiple($nids);

    $results = [];
    foreach ($nodes as $node) {
      $results[] = [
        'title' => $node->getTitle(),
        'body' => $node->get('body')->value,
        'created' => $node->getCreatedTime(),
      ];
    }
    return $results;
  }

  public function searchByKeyword($keyword) {
    $query = $this->database->query(
      "SELECT nid FROM {node_field_data} WHERE title LIKE '%" . $keyword . "%'"
    );
    return $query->fetchCol();
  }
}
