<?php

namespace Drupal\my_module\Plugin\Block;

use Drupal\Core\Block\BlockBase;

/**
 * Provides a 'RecentEvents' block.
 *
 * @Block(
 *   id = "recent_events_block",
 *   admin_label = @Translation("Recent Events"),
 *   category = @Translation("Custom")
 * )
 */
class RecentEventsBlock extends BlockBase {

  public function build() {
    $events = \Drupal::entityTypeManager()
      ->getStorage('node')
      ->loadByProperties([
        'type' => 'event',
        'status' => 1,
      ]);

    $items = [];
    foreach ($events as $event) {
      $items[] = $event->getTitle();
    }

    return [
      '#theme' => 'item_list',
      '#items' => $items,
      '#title' => $this->t('Upcoming Events'),
    ];
  }
}
