use Drupal\Core\Entity\EntityInterface;
use Drupal\Core\Form\FormStateInterface;

function my_module_node_presave(EntityInterface $node) {
  if ($node->bundle() == 'article') {
    $title = $node->getTitle();
    if (strlen($title) > 100) {
      $node->setTitle(substr($title, 0, 100) . '...');
    }
    $node->set('field_slug', strtolower(str_replace(' ', '-', $title)));
  }
}

function my_module_form_node_article_edit_form_alter(&$form, FormStateInterface $form_state) {
  $form['field_internal_notes']['#access'] = \Drupal::currentUser()->hasPermission('administer nodes');
  $form['#attached']['library'][] = 'my_module/admin_styles';
}
